// Parse phi3 art prompts and prepare for image generation
const raw = $input.first().json;
const product = $('🔀 Route by Product Type').first().json;

let promptData;
try {
  const content = raw?.message?.content || raw?.response || '';
  const match = content.match(/```json\n?([\s\S]*?)\n?```/) || content.match(/({[\s\S]*})/);
  promptData = JSON.parse((match ? match[1] || match[0] : content).trim());
} catch(e) {
  promptData = { prompts: [], error: e.message };
}

// Return each prompt as a separate item for parallel processing
const items = [];
for (const p of (promptData.prompts || [])) {
  items.push({
    json: {
      ...p,
      pack_name: promptData.pack_name,
      style_theme: promptData.style_theme,
      cover_prompt: promptData.cover_prompt,
      suggested_price: promptData.suggested_price,
      product_id: product.Product_Name?.toLowerCase().replace(/\s+/g, '_'),
      original_product: product
    }
  });
}
return items.length > 0 ? items : [{ json: { error: 'No prompts generated', product } }];

// Normalize image output from either Replicate or HuggingFace
const item = $input.first();
const json = item.json;
const binary = item.binary;

let imageUrl = null;
let imageBinary = null;
let source = 'unknown';

// From Replicate (returns URL)
if (json?.output && Array.isArray(json.output) && json.output[0]) {
  imageUrl = json.output[0];
  source = 'replicate';
}
// From HuggingFace (returns binary)
else if (binary?.data) {
  imageBinary = binary.data;
  source = 'huggingface';
}

return [{
  json: {
    filename: json.filename || `image_${Date.now()}`,
    pack_name: json.pack_name,
    product_id: json.product_id,
    style: json.style,
    image_url: imageUrl,
    source: source,
    generated_at: new Date().toISOString(),
    original_prompt_data: json
  },
  binary: imageBinary ? { data: imageBinary } : undefined
}];

