// Parse ebook content from llama3
const raw = $input.first().json;
const product = $('🔀 Route by Product Type').item.json;

let ebook;
try {
  const content = raw?.message?.content || raw?.response || '';
  const match = content.match(/```json\n?([\s\S]*?)\n?```/) || content.match(/({[\s\S]*})/);
  ebook = JSON.parse((match ? match[1] || match[0] : content).trim());
} catch(e) {
  ebook = { error: true, raw: raw?.message?.content?.substring(0, 200) };
}

ebook._product = product;
ebook._type = 'ebook';
ebook._created_at = new Date().toISOString();
return [{ json: ebook }];

// Build a complete, styled HTML ebook from the parsed content
const ebook = $input.first().json;

const coverColor = ebook.cover_color || '#2D3748';
const accentColor = ebook.accent_color || '#4299E1';
const title = ebook.title || 'Digital Guide';
const subtitle = ebook.subtitle || '';
const author = ebook.author || 'Digital Insights';

// Build chapters HTML
const chaptersHtml = (ebook.chapters || []).map(ch => `
  <div class="chapter" id="chapter-${ch.number}">
    <div class="chapter-header">
      <span class="chapter-number">Chapter ${ch.number}</span>
      <h2>${ch.title}</h2>
    </div>
    <div class="chapter-content">
      ${ch.content.split('\n').filter(p => p.trim()).map(p => `<p>${p}</p>`).join('')}
    </div>
    ${ch.key_takeaways && ch.key_takeaways.length ? `
    <div class="takeaways">
      <h4>Key Takeaways</h4>
      <ul>${ch.key_takeaways.map(t => `<li>${t}</li>`).join('')}</ul>
    </div>` : ''}
  </div>
`).join('');

// Table of contents
const tocHtml = (ebook.table_of_contents || []).map((item, i) =>
  `<li><a href="#chapter-${i+1}">${item}</a></li>`
).join('');

const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${title}</title>
  <style>
    @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;700&family=Open+Sans:wght@300;400;600&display=swap');
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: 'Open Sans', sans-serif; color: #2D3748; background: #fff; }
    .cover-page {
      background: linear-gradient(135deg, ${coverColor} 0%, ${accentColor} 100%);
      min-height: 100vh; display: flex; flex-direction: column;
      align-items: center; justify-content: center;
      text-align: center; padding: 60px 40px;
      page-break-after: always;
    }
    .cover-page h1 { font-family: 'Playfair Display', serif; font-size: 3em; color: #fff; margin-bottom: 20px; line-height: 1.2; }
    .cover-page .subtitle { font-size: 1.3em; color: rgba(255,255,255,0.85); margin-bottom: 30px; font-weight: 300; }
    .cover-page .tagline { font-size: 1em; color: rgba(255,255,255,0.7); font-style: italic; }
    .cover-page .author { margin-top: 60px; color: rgba(255,255,255,0.9); font-size: 1.1em; }
    .toc-page { padding: 80px 60px; page-break-after: always; }
    .toc-page h2 { font-family: 'Playfair Display', serif; font-size: 2em; color: ${coverColor}; margin-bottom: 30px; border-bottom: 3px solid ${accentColor}; padding-bottom: 10px; }
    .toc-page ol { list-style: none; counter-reset: toc-counter; }
    .toc-page ol li { counter-increment: toc-counter; padding: 12px 0; border-bottom: 1px solid #eee; font-size: 1.05em; }
    .toc-page ol li a { text-decoration: none; color: #2D3748; }
    .intro-page, .conclusion-page { padding: 80px 60px; page-break-after: always; }
    .intro-page h2, .conclusion-page h2 { font-family: 'Playfair Display', serif; font-size: 2em; color: ${coverColor}; margin-bottom: 30px; }
    .intro-page p, .conclusion-page p { font-size: 1.05em; line-height: 1.8; margin-bottom: 16px; color: #4A5568; }
    .chapter { padding: 80px 60px; page-break-after: always; }
    .chapter-header { margin-bottom: 40px; }
    .chapter-number { font-size: 0.85em; color: ${accentColor}; font-weight: 600; text-transform: uppercase; letter-spacing: 3px; }
    .chapter h2 { font-family: 'Playfair Display', serif; font-size: 2.2em; color: ${coverColor}; margin-top: 10px; line-height: 1.3; }
    .chapter-content p { font-size: 1.05em; line-height: 1.9; margin-bottom: 18px; color: #4A5568; }
    .takeaways { background: linear-gradient(135deg, ${coverColor}11, ${accentColor}22); border-left: 4px solid ${accentColor}; padding: 25px 30px; margin-top: 40px; border-radius: 0 8px 8px 0; }
    .takeaways h4 { color: ${coverColor}; font-size: 1.1em; margin-bottom: 15px; font-weight: 600; }
    .takeaways ul li { padding: 6px 0; color: #4A5568; font-size: 0.95em; }
    .about-page { background: #F7FAFC; padding: 80px 60px; text-align: center; }
    .about-page h3 { font-family: 'Playfair Display', serif; font-size: 1.8em; color: ${coverColor}; margin-bottom: 20px; }
    .about-page p { font-size: 1em; line-height: 1.8; color: #718096; max-width: 500px; margin: 0 auto; }
    .back-cover { background: linear-gradient(135deg, ${coverColor} 0%, ${accentColor} 100%); min-height: 60vh; display: flex; align-items: center; justify-content: center; padding: 60px; text-align: center; }
    .back-cover p { color: rgba(255,255,255,0.9); font-size: 1.2em; line-height: 1.8; max-width: 500px; font-style: italic; }
    @media print { * { -webkit-print-color-adjust: exact; print-color-adjust: exact; } }
  </style>
</head>
<body>
  <div class="cover-page">
    <h1>${title}</h1>
    <div class="subtitle">${subtitle}</div>
    <div class="tagline">${ebook.tagline || ''}</div>
    <div class="author">By ${author}</div>
  </div>
  <div class="toc-page">
    <h2>Table of Contents</h2>
    <ol>${tocHtml}</ol>
  </div>
  <div class="intro-page">
    <h2>Introduction</h2>
    ${(ebook.introduction || '').split('\n').filter(p=>p.trim()).map(p=>`<p>${p}</p>`).join('')}
  </div>
  ${chaptersHtml}
  <div class="conclusion-page">
    <h2>Conclusion</h2>
    ${(ebook.conclusion || '').split('\n').filter(p=>p.trim()).map(p=>`<p>${p}</p>`).join('')}
  </div>
  <div class="about-page">
    <h3>About the Author</h3>
    <p>${ebook.about_page || ''}</p>
  </div>
  <div class="back-cover">
    <p>${ebook.back_cover_text || ''}</p>
  </div>
</body>
</html>`;

return [{ json: { ...ebook, html_content: html, _ready_for_pdf: true } }];

