// Parse Notion template and prepare Notion API calls
const raw = $input.first().json;
const product = $('🔀 Route by Product Type').item.json;

let notionData;
try {
  const content = raw?.message?.content || raw?.response || '';
  const match = content.match(/```json\n?([\s\S]*?)\n?```/) || content.match(/({[\s\S]*})/);
  notionData = JSON.parse((match ? match[1] || match[0] : content).trim());
} catch(e) {
  notionData = { error: e.message, page_content: [] };
}

// Convert llama3 content to Notion API block format
const blocks = (notionData.page_content || []).map(item => {
  if (item.type === 'heading_1') return { object:'block', type:'heading_1', heading_1:{ rich_text:[{type:'text',text:{content:item.text}}] }};
  if (item.type === 'heading_2') return { object:'block', type:'heading_2', heading_2:{ rich_text:[{type:'text',text:{content:item.text}}] }};
  if (item.type === 'paragraph') return { object:'block', type:'paragraph', paragraph:{ rich_text:[{type:'text',text:{content:item.text}}] }};
  if (item.type === 'bulleted_list_item') return { object:'block', type:'bulleted_list_item', bulleted_list_item:{ rich_text:[{type:'text',text:{content:item.text}}] }};
  if (item.type === 'callout') return { object:'block', type:'callout', callout:{ rich_text:[{type:'text',text:{content:item.text}}], icon:{type:'emoji',emoji:item.icon||'💡'} }};
  if (item.type === 'divider') return { object:'block', type:'divider', divider:{} };
  return { object:'block', type:'paragraph', paragraph:{ rich_text:[{type:'text',text:{content:item.text||''}}] }};
}).filter(Boolean);

return [{
  json: {
    ...notionData,
    notion_blocks: blocks,
    product_id: product.Product_Name?.toLowerCase().replace(/\s+/g,'_'),
    _product: product,
    _type: 'notion'
  }
}];

// Collect all product files from all pipelines and prepare for packaging
// This node receives outputs from all 4 pipelines merged

const items = $input.all();
const products = [];

for (const item of items) {
  const data = item.json;
  if (!data) continue;

  const type = data._type || data.original_product?._type || 'unknown';
  const productId = data.product_id || `product_${Date.now()}`;

  products.push({
    product_id: productId,
    type: type,
    files: data.pdf_path ? [data.pdf_path] : [],
    image_url: data.image_url || null,
    notion_url: data.url ? `https://notion.so/${data.id?.replace(/-/g,'')}` : null,
    metadata: {
      title: data.title || data.pack_name || data.template_name || productId,
      price: data.suggested_price || null,
      cover_prompt: data.cover_prompt || null
    },
    raw: data
  });
}

return [{ json: { products_to_package: products, count: products.length, packaged_at: new Date().toISOString() } }];

// Parse zip result and prepare for Google Drive upload
const zipOutput = $input.first().json?.stdout || '';
const packageData = $('🔀 Collect All Product Files').first().json;

const lines = zipOutput.split('\n');
const resultLine = lines.find(l => l.startsWith('SUCCESS|') || l.startsWith('FAILED|'));

let zipPath = null;
let zipSize = null;
let success = false;

if (resultLine && resultLine.startsWith('SUCCESS|')) {
  const parts = resultLine.split('|');
  zipPath = parts[1];
  zipSize = parts[2];
  success = true;
}

const productId = packageData.products_to_package?.[0]?.product_id || `product_${Date.now()}`;

return [{
  json: {
    zip_success: success,
    zip_path: zipPath,
    zip_size: zipSize,
    product_id: productId,
    drive_filename: `${productId}_digital_product.zip`,
    package_data: packageData,
    _stage: 'ready_for_drive_upload'
  }
}];

// Build final product record with all URLs and metadata
const driveFile = $('☁️ Upload ZIP to Google Drive').first().json;
const zipData = $('⚙️ Parse ZIP Result').first().json;
const packageData = zipData.package_data;
const productMeta = packageData?.products_to_package?.[0]?.metadata || {};

const fileId = driveFile?.id;
const driveUrl = fileId ? `https://drive.google.com/file/d/${fileId}/view` : null;
const downloadUrl = fileId ? `https://drive.google.com/uc?export=download&id=${fileId}` : null;

const finalProduct = {
  product_id: zipData.product_id,
  title: productMeta.title || zipData.product_id,
  price: productMeta.price || 9.99,
  zip_path: zipData.zip_path,
  zip_size: zipData.zip_size,
  drive_file_id: fileId,
  drive_url: driveUrl,
  download_url: downloadUrl,
  created_at: new Date().toISOString(),
  status: 'CREATION_COMPLETE',
  ready_to_publish: true,
  _package: packageData
};

return [{ json: finalProduct }];
